Our Express auth middleware is letting unauthenticated requests through intermittently. Here's the code:

const authMiddleware = async (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token || token === 'undefined') {
    return res.status(401).json({ error: 'No token' });
  }
  try {
    const user = await verifyToken(token);
    req.user = user;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token expired' });
    }
    next();
  }
};

We're running a TypeScript service on Node 18. It handles Stripe webhooks. Started getting timeouts this week — but only for payment_intent.succeeded events, other event types work fine. Here's the handler:

app.post('/webhook', express.raw({ type: 'application/json' }), async (req, res) => {
  const sig = req.headers['stripe-signature'];
  let event;
  try {
    event = stripe.webhooks.constructEvent(req.body, sig, process.env.STRIPE_WEBHOOK_SECRET);
  } catch (err) {
    return res.status(400).send(`Webhook Error: ${err.message}`);
  }
  await processEvent(event);
  res.json({ received: true });
});
